SELECT SUM(storage_size) AS total_storage_size
FROM storage_accounts
WHERE status = 'active' AND subscription_id = 1;

SELECT SUM(storage_size) AS total_storage
FROM storage_accounts
WHERE status = 'active';

SELECT MAX(updated_at) AS most_recent_update_date
FROM management_policies
WHERE management_policy_name = 'security';

SELECT account_name
FROM storage_accounts
WHERE storage_size = (SELECT MAX(storage_size) FROM storage_accounts);

SELECT management_policy_name
FROM management_policies
WHERE created_at = (
    SELECT MAX(created_at)
    FROM management_policies
);

SELECT storage_size AS total_storage_size
FROM storage_accounts
WHERE updated_at = (
  SELECT MAX(updated_at)
  FROM storage_accounts
);

SELECT account_id AS answer
FROM storage_accounts
WHERE created_at = '2023-01-01';

SELECT AVG(storage_size) AS average_storage_size
FROM storage_accounts
WHERE subscription_id = 1;

SELECT DISTINCT mp.management_policy_name
FROM management_policies AS mp
JOIN storage_accounts AS sa ON mp.management_policy_id = sa.management_policy_id;
